css:
.loader {
      display: inline-grid;
      grid-template-columns: repeat(3, 9px);
      gap: 5px;
    }
    .loader i {
      width: 9px;
      height: 9px;
      border-radius: 4px;
      background: var(--loader-color);
      animation: gridFlash 0.95s ease-in-out infinite;
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: 0.08s; }
.loader i:nth-child(3) { animation-delay: 0.16s; }
.loader i:nth-child(4) { animation-delay: 0.08s; }
.loader i:nth-child(5) { animation-delay: 0.16s; }
.loader i:nth-child(6) { animation-delay: 0.24s; }
.loader i:nth-child(7) { animation-delay: 0.16s; }
.loader i:nth-child(8) { animation-delay: 0.24s; }
.loader i:nth-child(9) { animation-delay: 0.32s; }
    @keyframes gridFlash { 0%, 70%, 100% { opacity: .25; transform: scale(.75); } 35% { opacity: 1; transform: scale(1); } }
